INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Calves-SMR','Calves-SMR','pantorrillas',ARRAY[]::text[],'foam roller','stretching',ARRAY['Begin seated on the floor. Place a foam roller underneath your lower leg. Your other leg can either be crossed over the opposite or be placed on the floor, supporting some of your weight. This will be your starting position.','Place your hands to your side or just behind you, and press down to raise your hips off of the floor, placing much of your weight against your calf muscle. Roll from below the knee to above the ankle, pausing at points of tension for 10-30 seconds. Repeat for the other leg.'],'Begin seated on the floor. Place a foam roller underneath your lower leg. Your other leg can either be crossed over the opposite or be placed on the floor, supporting some of your weight. This will be your starting position. Place your hands to your side or just behind you, and press down to raise your hips off of the floor, placing much of your weight against your calf muscle. Roll from below the knee to above the ankle, pausing at points of tension for 10-30 seconds. Repeat for the other leg.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Calves-SMR/0.jpg','exercisedb',true),('Car_Deadlift','Car Deadlift','cuádriceps',ARRAY['antebrazos','glúteos','isquiotibiales','espalda baja','trapecios'],'otro','strongman',ARRAY['This event apparatus typically has neutral grip handles, however some have a straight bar that you can approach like a normal deadlift. The apparatus can be loaded with a vehicle or other heavy objects such as tractor tires or kegs.','Center yourself between the handles if you are a strong squatter, or back a couple inches if you are a strong deadlifter. You feet should be about hip width apart. Bend at the hip to grip the handles. With your feet and your grip set, take a big breath and then lower your hips and flex the knees.','Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward. As the weight comes up, pull your shoulder blades together as you drive your hips forward.','Lower the weight by bending at the hips and guiding it to the floor.'],'This event apparatus typically has neutral grip handles, however some have a straight bar that you can approach like a normal deadlift. The apparatus can be loaded with a vehicle or other heavy objects such as tractor tires or kegs. Center yourself between the handles if you are a strong squatter, or back a couple inches if you are a strong deadlifter. You feet should be about hip width apart. Bend at the hip to grip the handles. With your feet and your grip set, take a big breath and then lower your hips and flex the knees. Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward. As the weight comes up, pull your shoulder blades together as you drive your hips forward. Lower the weight by bending at the hips and guiding it to the floor.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Car_Deadlift/0.jpg','exercisedb',true),('Car_Drivers','Car Drivers','hombros',ARRAY['antebrazos'],'barra','strength',ARRAY['While standing upright, hold a barbell plate in both hands at the 3 and 9 o''''clock positions. Your palms should be facing each other and your arms should be extended straight out in front of you. This will be your starting position.','Initiate the movement by rotating the plate as far to one side as possible. Use the same type of movement you would use to turn a steering wheel to one side.','Reverse the motion, turning it all the way to the opposite side.','Repeat for the recommended amount of repetitions.'],'While standing upright, hold a barbell plate in both hands at the 3 and 9 o''clock positions. Your palms should be facing each other and your arms should be extended straight out in front of you. This will be your starting position. Initiate the movement by rotating the plate as far to one side as possible. Use the same type of movement you would use to turn a steering wheel to one side. Reverse the motion, turning it all the way to the opposite side. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Car_Drivers/0.jpg','exercisedb',true),('Carioca_Quick_Step','Carioca Quick Step','aductores',ARRAY['abdominales','abductores','pantorrillas','glúteos','isquiotibiales','cuádriceps'],NULL,'plyometrics',ARRAY['Begin with your feet a few inches apart and your left arm up in a relaxed, athletic position.','With your right foot, quick step behind and pull the knee up.','Fire your arms back up when you pull the right knee, being sure that your knee goes straight up and down. Avoid turning your feet as you move and continue to look forward as you move to the side.'],'Begin with your feet a few inches apart and your left arm up in a relaxed, athletic position. With your right foot, quick step behind and pull the knee up. Fire your arms back up when you pull the right knee, being sure that your knee goes straight up and down. Avoid turning your feet as you move and continue to look forward as you move to the side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Carioca_Quick_Step/0.jpg','exercisedb',true),('Cat_Stretch','Cat Stretch','espalda baja',ARRAY['espalda media','trapecios'],NULL,'stretching',ARRAY['Position yourself on the floor on your hands and knees.','Pull your belly in and round your spine, lower back, shoulders, and neck, letting your head drop.','Hold for 15 seconds.'],'Position yourself on the floor on your hands and knees. Pull your belly in and round your spine, lower back, shoulders, and neck, letting your head drop. Hold for 15 seconds.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cat_Stretch/0.jpg','exercisedb',true),('Catch_and_Overhead_Throw','Catch and Overhead Throw','dorsales',ARRAY['abdominales','pecho','hombros'],'balón medicinal','plyometrics',ARRAY['Begin standing while facing a wall or a partner.','Using both hands, position the ball behind your head, stretching as much as possible, and forcefully throw the ball forward.','Ensure that you follow your throw through, being prepared to receive your rebound from your throw. If you are throwing against the wall, make sure that you stand close enough to the wall to receive the rebound, and aim a little higher than you would with a partner.'],'Begin standing while facing a wall or a partner. Using both hands, position the ball behind your head, stretching as much as possible, and forcefully throw the ball forward. Ensure that you follow your throw through, being prepared to receive your rebound from your throw. If you are throwing against the wall, make sure that you stand close enough to the wall to receive the rebound, and aim a little higher than you would with a partner.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Catch_and_Overhead_Throw/0.jpg','exercisedb',true),('Chain_Handle_Extension','Chain Handle Extension','tríceps',ARRAY[]::text[],'otro','powerlifting',ARRAY['You will need two cable handle attachments and a flat bench, as well as chains, for this exercise. Clip the middle of the chains to the handles, and position yourself on the flat bench. Your elbows should be pointing straight up.','Begin by extending through the elbow, keeping your upper arm still, with your wrists pronated.','Pause at the lockout, and reverse the motion to return to the starting position.'],'You will need two cable handle attachments and a flat bench, as well as chains, for this exercise. Clip the middle of the chains to the handles, and position yourself on the flat bench. Your elbows should be pointing straight up. Begin by extending through the elbow, keeping your upper arm still, with your wrists pronated. Pause at the lockout, and reverse the motion to return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chain_Handle_Extension/0.jpg','exercisedb',true),('Chain_Press','Chain Press','pecho',ARRAY['hombros','tríceps'],'otro','powerlifting',ARRAY['Begin by connecting the chains to the cable handle attachments. Position yourself on the flat bench in the same position as for a dumbbell press. Your wrists should be pronated and arms perpendicular to the floor. This will be your starting position.','Lower the chains by flexing the elbows, unloading some of the chain onto the floor.','Continue until your elbow forms a 90 degree angle, and then reverse the motion by extending through the elbow to lockout.'],'Begin by connecting the chains to the cable handle attachments. Position yourself on the flat bench in the same position as for a dumbbell press. Your wrists should be pronated and arms perpendicular to the floor. This will be your starting position. Lower the chains by flexing the elbows, unloading some of the chain onto the floor. Continue until your elbow forms a 90 degree angle, and then reverse the motion by extending through the elbow to lockout.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chain_Press/0.jpg','exercisedb',true),('Chair_Leg_Extended_Stretch','Chair Leg Extended Stretch','isquiotibiales',ARRAY['aductores'],'otro','stretching',ARRAY['Sit upright in a chair and grip the seat on the sides.','Raise one leg, extending the knee, flexing the ankle as you do so.','Slowly move that leg outward as far as you can, and then back to the center and down.','Repeat for your other leg.'],'Sit upright in a chair and grip the seat on the sides. Raise one leg, extending the knee, flexing the ankle as you do so. Slowly move that leg outward as far as you can, and then back to the center and down. Repeat for your other leg.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chair_Leg_Extended_Stretch/0.jpg','exercisedb',true),('Chair_Lower_Back_Stretch','Chair Lower Back Stretch','dorsales',ARRAY['espalda baja'],NULL,'stretching',ARRAY['Sit upright on a chair.','Bend to one side with your arm over your head. You can hold onto the chair with your free hand.','Hold for 10 seconds, and repeat for your other side.'],'Sit upright on a chair. Bend to one side with your arm over your head. You can hold onto the chair with your free hand. Hold for 10 seconds, and repeat for your other side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chair_Lower_Back_Stretch/0.jpg','exercisedb',true);